"use client";

import { MainLayout } from "@/components/layout/main-layout";
import { 
  MessageSquare, 
  Star, 
  Send, 
  User, 
  Calendar,
  Quote
} from "lucide-react";
import { useState, useEffect } from "react";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// Mock Data
const MOCK_FEEDBACK = [
  { id: "1", intern: "Alice Johnson", message: "Great experience so far! The mentors are very helpful.", rating: 5, date: "2024-03-10" },
  { id: "2", intern: "Bob Smith", message: "I've learned a lot about Next.js and Tailwind.", rating: 4, date: "2024-03-12" },
  { id: "3", intern: "Charlie Brown", message: "The onboarding process could be smoother, but the work is interesting.", rating: 3, date: "2024-03-15" },
];

export default function FeedbackPage() {
  const [role, setRole] = useState<string>("intern");
  const [rating, setRating] = useState(0);
  const [message, setMessage] = useState("");

  useEffect(() => {
    const getCookie = (name: string) => {
        const value = `; ${document.cookie}`;
        const parts = value.split(`; ${name}=`);
        if (parts.length === 2) return parts.pop()?.split(';').shift();
        return '';
      };

      const token = getCookie('auth-token');
      if (token) {
        try {
          const payload = JSON.parse(atob(token.split('.')[1]));
          setRole(payload.role || "intern");
        } catch (e) {
          setRole("intern");
        }
      }
  }, []);

  return (
    <MainLayout>
      <div className="space-y-8">
        {/* Header */}
        <div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight">
            Feedback & Reviews
          </h1>
          <p className="text-slate-500 mt-2 font-medium">
            {role === 'intern' 
              ? "Tell us about your internship experience." 
              : "Review anonymous feedback from your interns."}
          </p>
        </div>

        {role === 'intern' ? (
          /* Intern View: Submission Form */
          <div className="max-w-2xl bg-white p-8 rounded-3xl border border-slate-100 shadow-sm shadow-slate-200/40">
             <div className="flex items-center gap-4 mb-8">
               <div className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl">
                 <MessageSquare size={24} />
               </div>
               <div>
                 <h3 className="text-lg font-bold text-slate-900">Share Your Thoughts</h3>
                 <p className="text-sm text-slate-400">Your feedback helps us improve the program.</p>
               </div>
             </div>

             <form className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-3">Overall Rating</label>
                  <div className="flex gap-2">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button
                        key={star}
                        type="button"
                        onClick={() => setRating(star)}
                        className={cn(
                          "p-2 rounded-xl transition-all border",
                          rating >= star 
                            ? "bg-amber-50 border-amber-200 text-amber-500" 
                            : "bg-slate-50 border-slate-200 text-slate-300 hover:border-amber-200"
                        )}
                      >
                        <Star size={24} fill={rating >= star ? "currentColor" : "none"} />
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-3">Your Message</label>
                  <textarea
                    rows={4}
                    placeholder="Describe your experience, challenges, and what you've learned..."
                    className="block w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                  />
                </div>

                <button
                  type="button"
                  className="w-full py-4 px-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-sm font-bold shadow-lg shadow-indigo-200 transition-all flex items-center justify-center"
                >
                  <Send size={18} className="mr-2" />
                  Submit Feedback
                </button>
             </form>
          </div>
        ) : (
          /* Admin/Department View: Feedback List */
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {MOCK_FEEDBACK.map((fb) => (
              <div 
                key={fb.id}
                className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-all group relative"
              >
                <div className="absolute top-6 right-6 text-slate-100 group-hover:text-indigo-50 transition-colors">
                  <Quote size={40} />
                </div>

                <div className="flex items-center gap-2 mb-4">
                  {[...Array(5)].map((_, i) => (
                    <Star 
                      key={i} 
                      size={14} 
                      className={i < fb.rating ? "text-amber-400 fill-amber-400" : "text-slate-200 fill-slate-200"} 
                    />
                  ))}
                </div>

                <p className="text-slate-700 text-sm leading-relaxed mb-6 font-medium">
                  "{fb.message}"
                </p>

                <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                   <div className="flex items-center gap-2">
                     <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xs">
                        <User size={14} />
                     </div>
                     <span className="text-xs font-bold text-slate-700">{fb.intern}</span>
                   </div>
                   <div className="flex items-center gap-1 text-slate-400">
                     <Calendar size={12} />
                     <span className="text-[10px] font-bold">{fb.date}</span>
                   </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </MainLayout>
  );
}

"use server";

import { cookies } from "next/headers";
import { createToken } from "@/lib/auth-utils";
import { Role } from "@/types";

export async function loginAction(formData: FormData) {
  const email = formData.get("email") as string;
  const password = formData.get("password") as string;

  // MOCK AUTHENTICATION LOGIC
  // In a real app, you would verify this against Hasura/PostgreSQL
  let role: Role = 'intern';
  let userId = 'mock-user-id';
  let departmentId = null;

  if (email.includes('admin')) {
    role = 'admin';
  } else if (email.includes('dept')) {
    role = 'department';
    departmentId = 'mock-dept-id';
  }

  const token = await createToken({ 
    userId, 
    role, 
    departmentId 
  });

  const cookieStore = await cookies();
  cookieStore.set("auth-token", token, {
    httpOnly: false, // Set to false so Apollo Client can read it on the client side
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 60 * 60 * 2, // 2 hours
    path: "/",
  });

  return { success: true, role };
}

export async function logoutAction() {
  const cookieStore = await cookies();
  cookieStore.delete("auth-token");
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { loginAction } from "./actions";
import { Lock, Mail, Loader2 } from "lucide-react";

export default function LoginPage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const formData = new FormData(e.currentTarget);
      const res = await loginAction(formData);

      if (res.success) {
        router.push("/dashboard");
      } else {
        setError("Invalid credentials");
      }
    } catch (err) {
      setError("An error occurred during login");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
      <div className="max-w-md w-full">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-indigo-600 text-white shadow-xl shadow-indigo-200 mb-4 ring-4 ring-indigo-50">
            <Lock size={32} />
          </div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">
            Welcome Back
          </h2>
          <p className="text-slate-500 mt-2 font-medium">
            Sign in to manage your internship program
          </p>
        </div>

        {/* Card */}
        <div className="bg-white p-8 rounded-3xl shadow-xl shadow-slate-200/60 border border-slate-100">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label 
                htmlFor="email" 
                className="block text-sm font-semibold text-slate-700 mb-2"
              >
                Email Address
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-400">
                  <Mail size={18} />
                </div>
                <input
                  id="email"
                  name="email"
                  type="email"
                  required
                  placeholder="admin@example.com"
                  className="block w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                />
              </div>
            </div>

            <div>
              <label 
                htmlFor="password" 
                className="block text-sm font-semibold text-slate-700 mb-2"
              >
                Password
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-400">
                  <Lock size={18} />
                </div>
                <input
                  id="password"
                  name="password"
                  type="password"
                  required
                  placeholder="••••••••"
                  className="block w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                />
              </div>
            </div>

            {error && (
              <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl text-rose-600 text-sm font-medium">
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full flex items-center justify-center py-4 px-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-sm font-bold shadow-lg shadow-indigo-200 transition-all active:scale-[0.98] disabled:opacity-70 disabled:active:scale-100"
            >
              {loading ? (
                <Loader2 className="animate-spin mr-2" size={20} />
              ) : null}
              {loading ? "Signing in..." : "Continue to Dashboard"}
            </button>
          </form>

          {/* Prompt info */}
          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
            <p className="text-sm text-slate-400">
              Mock account hints: <br/>
              <span className="font-semibold text-slate-600">admin@...</span> (Admin) | 
              <span className="font-semibold text-slate-600"> dept@...</span> (Dept)
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

